mapper.select:
select count(*)
from functional_case
where deleted = 0

  and project_id = #{projectId,jdbcType=VARCHAR}

  and create_time >= #{startTime,jdbcType=BIGINT}
  and create_time <= #{endTime,jdbcType=BIGINT}

select tpcm.case_id, fc.name as case_name, sum(tpcm.exec_count) as exec_count, sum(tpcm.total_time_ms) as total_duration, COALESCE(cmd.cs_score, 0) as cs_score, cmd.complexity_level, max(tpcm.last_exec_result) as last_exec_result from spotter_efficiency.test_plan_case_metrics tpcm left join spotter_efficiency.case_metrics_detail cmd on tpcm.case_id COLLATE utf8mb4_general_ci = cmd.case_id COLLATE utf8mb4_general_ci left join spotter_metersphere.functional_case fc on tpcm.case_id COLLATE utf8mb4_general_ci = fc.id COLLATE utf8mb4_general_ci where 1=1
and tpcm.project_id = #{projectId,jdbcType=VARCHAR}
and tpcm.create_time >= #{startTime,jdbcType=BIGINT}
and tpcm.create_time <= #{endTime,jdbcType=BIGINT}
group by tpcm.case_id, fc.name, cmd.cs_score, cmd.complexity_level having sum(tpcm.exec_count) >= #{threshold,jdbcType=INTEGER} order by exec_count desc limit 20

select count(*)
from test_plan_functional_case
where test_plan_id = #{planId,jdbcType=VARCHAR}

select count(*)
from functional_case
where create_user = #{userId,jdbcType=VARCHAR}
  and deleted = 0
  and create_time >= #{startTime,jdbcType=BIGINT}
  and create_time <= #{endTime,jdbcType=BIGINT}

select distinct ccl.case_id
from spotter_efficiency.case_change_log ccl
where 1=1
and (ccl.change_reason is null or ccl.change_reason != 'CASE_COPY')
and ccl.case_id is not null

    and ccl.project_id in

        #{id,jdbcType=VARCHAR}



    and ccl.project_id = #{projectId,jdbcType=VARCHAR}


    and ccl.operator = #{userId,jdbcType=VARCHAR}


    and ccl.create_time >= #{startTime,jdbcType=BIGINT}


    and ccl.create_time <= #{endTime,jdbcType=BIGINT}


    and (
        exists (select 1 from test_plan_functional_case tpf where tpf.functional_case_id COLLATE utf8mb4_general_ci = ccl.case_id COLLATE utf8mb4_general_ci)
        or exists (
            select 1 from functional_case fc_2lib
            inner join functional_case_module fcm_2lib on fc_2lib.module_id = fcm_2lib.id
            where fc_2lib.id COLLATE utf8mb4_general_ci = ccl.case_id COLLATE utf8mb4_general_ci and fc_2lib.deleted = 0
              and fcm_2lib.name in

                #{name,jdbcType=VARCHAR}

        )
    )

select distinct cmd.case_id
from spotter_efficiency.case_metrics_detail cmd

    inner join functional_case fc on cmd.case_id COLLATE utf8mb4_general_ci = fc.id COLLATE utf8mb4_general_ci

where 1=1

    and cmd.project_id in

        #{id,jdbcType=VARCHAR}



    and cmd.project_id = #{projectId,jdbcType=VARCHAR}


    and fc.create_user = #{userId,jdbcType=VARCHAR}

and cmd.case_source_type in ('REUSE', 'COPY')

    and cmd.create_time >= #{startTime,jdbcType=BIGINT}


    and cmd.create_time <= #{endTime,jdbcType=BIGINT}

and cmd.case_id is not null

select tpcm.case_id
from spotter_efficiency.test_plan_case_metrics tpcm
where tpcm.create_time >= #{startTime,jdbcType=BIGINT}
  and tpcm.create_time <= #{endTime,jdbcType=BIGINT}

    and tpcm.project_id = #{projectId,jdbcType=VARCHAR}

group by tpcm.case_id
having sum(tpcm.exec_count) >= #{threshold,jdbcType=INTEGER}

select tpcm.case_id
from spotter_efficiency.test_plan_case_metrics tpcm
join spotter_metersphere.functional_case fc 
    on fc.id COLLATE utf8mb4_general_ci = tpcm.case_id COLLATE utf8mb4_general_ci
where tpcm.create_time >= #{startTime,jdbcType=BIGINT}
  and tpcm.create_time <= #{endTime,jdbcType=BIGINT}
  and fc.create_user = #{userId,jdbcType=VARCHAR}
group by tpcm.case_id
having sum(tpcm.exec_count) >= #{threshold,jdbcType=INTEGER}

select cmd.case_id
from spotter_efficiency.case_metrics_detail cmd
where cmd.case_id in

    #{caseId,jdbcType=VARCHAR}


    and cmd.create_time >= #{startTime,jdbcType=BIGINT}


    and cmd.create_time <= #{endTime,jdbcType=BIGINT}

select fc.id
from functional_case fc
where fc.id in

    #{caseId,jdbcType=VARCHAR}

and fc.deleted = 0

    and fc.create_time >= #{startTime,jdbcType=BIGINT}


    and fc.create_time <= #{endTime,jdbcType=BIGINT}

select cmd.case_id
from spotter_efficiency.case_metrics_detail cmd
where 1=1

    and cmd.project_id in

        #{id,jdbcType=VARCHAR}



    and cmd.project_id = #{projectId,jdbcType=VARCHAR}


    and cmd.create_user = #{userId,jdbcType=VARCHAR}


    and cmd.create_time >= #{startTime,jdbcType=BIGINT}


    and cmd.create_time <= #{endTime,jdbcType=BIGINT}


