        where fc_ev.id = cmd.case_id and fc_ev.deleted = 0
          and fcm_ev.name = #{versionCaseModuleName,jdbcType=VARCHAR}
    )

select fc.id
from functional_case fc
inner join functional_case_module fcm on fc.module_id = fcm.id
where fc.deleted = 0 and fcm.name in

    #{name,jdbcType=VARCHAR}


    and fc.create_time < #{endTime,jdbcType=BIGINT}


    and fc.project_id = #{projectId,jdbcType=VARCHAR}

select fc.id
from functional_case fc
inner join functional_case_module fcm on fc.module_id = fcm.id
where fc.deleted = 0 and fcm.name in

    #{name,jdbcType=VARCHAR}


    and fc.create_time <= #{endTime,jdbcType=BIGINT}


    and fc.project_id in

        #{id,jdbcType=VARCHAR}



    and fc.project_id = #{projectId,jdbcType=VARCHAR}

select fc.id
from functional_case fc
inner join functional_case_module fcm on fc.module_id = fcm.id
where fc.deleted = 0 and fcm.name in

    #{name,jdbcType=VARCHAR}


    and fc.project_id in

        #{id,jdbcType=VARCHAR}



    and fc.project_id = #{projectId,jdbcType=VARCHAR}

select fc.id
from functional_case fc
where (fc.deleted IS NULL OR fc.deleted = 0)

    and fc.project_id in

        #{id,jdbcType=VARCHAR}



    and fc.project_id = #{projectId,jdbcType=VARCHAR}

select fc.id
from functional_case fc
inner join functional_case_module fcm on fc.module_id = fcm.id
where fc.deleted = 0 and fcm.name in

    #{name,jdbcType=VARCHAR}


    and fc.create_time >= #{startTime,jdbcType=BIGINT}


    and fc.create_time <= #{endTime,jdbcType=BIGINT}


    and fc.project_id in

        #{id,jdbcType=VARCHAR}



    and fc.project_id = #{projectId,jdbcType=VARCHAR}

select id from functional_case
where deleted = 0

    and project_id in

        #{id,jdbcType=VARCHAR}



    and project_id = #{projectId,jdbcType=VARCHAR}


    and create_time >= #{startTime,jdbcType=BIGINT}


    and create_time <= #{endTime,jdbcType=BIGINT}

select fc.id
from functional_case fc
inner join functional_case_module fcm on fc.module_id = fcm.id
where fc.deleted = 0
and fcm.name in

    #{name,jdbcType=VARCHAR}


    and fc.create_time >= #{startTime,jdbcType=BIGINT}


    and fc.create_time <= #{endTime,jdbcType=BIGINT}


    and fc.project_id in

        #{id,jdbcType=VARCHAR}



    and fc.project_id = #{projectId,jdbcType=VARCHAR}

and not exists (select 1 from test_plan_functional_case tpfc where tpfc.functional_case_id COLLATE utf8mb4_general_ci = fc.id COLLATE utf8mb4_general_ci)
and not exists (select 1 from spotter_efficiency.test_plan_case_metrics tpcm where tpcm.case_id COLLATE utf8mb4_general_ci = fc.id COLLATE utf8mb4_general_ci and tpcm.exec_count > 0)

select distinct tpcm.case_id
from spotter_efficiency.test_plan_case_metrics tpcm
where tpcm.case_id in

    #{caseId,jdbcType=VARCHAR}

and tpcm.exec_count > 0

    and tpcm.create_time >= #{startTime,jdbcType=BIGINT}


    and tpcm.create_time <= #{endTime,jdbcType=BIGINT}

select distinct fc.id as caseId, fc.name as caseName, fc.num as caseNum, fc.module_id as moduleId, fc.project_id as projectId, fc.create_user as createUser, fc.create_time as createTime, fc.update_time as updateTime, CONVERT(fcb.prerequisite USING utf8mb4) as prerequisite, CONVERT(fcb.description USING utf8mb4) as description, cmd.cs_score as csScore, cmd.cs_factor_c1 as csFactorC1, cmd.cs_factor_c2 as csFactorC2, cmd.cs_factor_c3 as csFactorC3, cmd.cs_factor_c4 as csFactorC4, cmd.cs_factor_c5 as csFactorC5, cmd.cs_factor_c6 as csFactorC6 from spotter_efficiency.case_metrics_detail cmd inner join functional_case fc on cmd.case_id COLLATE utf8mb4_general_ci = fc.id COLLATE utf8mb4_general_ci left join functional_case_blob fcb on fc.id = fcb.id
and cmd.case_source_type in ('REUSE', 'COPY')
and cmd.create_time >= #{startTime,jdbcType=BIGINT}
and cmd.create_time <= #{endTime,jdbcType=BIGINT}
inner join spotter_efficiency.case_change_log ccl on fc.id = ccl.case_id
and ccl.create_time >= #{startTime,jdbcType=BIGINT}
and ccl.create_time <= #{endTime,jdbcType=BIGINT}
inner join ( select case_id from spotter_efficiency.test_plan_case_metrics where 1=1
and create_time >= #{startTime,jdbcType=BIGINT}
and create_time <= #{endTime,jdbcType=BIGINT}
group by case_id having sum(exec_count) >= 3 ) cer_high on fc.id = cer_high.case_id
where fc.deleted = 0
and fc.create_user = #{dimensionValue,jdbcType=VARCHAR}
and fc.project_id = #{dimensionValue,jdbcType=VARCHAR}
and fc.create_time >= #{startTime,jdbcType=BIGINT}
and fc.create_time <= #{endTime,jdbcType=BIGINT}
order by cmd.cs_score desc, fc.create_time desc
limit #{offset}, #{limit}

select count(distinct fc.id)
from spotter_efficiency.case_metrics_detail cmd
inner join functional_case fc on cmd.case_id COLLATE utf8mb4_general_ci = fc.id COLLATE utf8mb4_general_ci




        and cmd.case_source_type in ('REUSE', 'COPY')

            and cmd.create_time >= #{startTime,jdbcType=BIGINT}


            and cmd.create_time <= #{endTime,jdbcType=BIGINT}



        inner join spotter_efficiency.case_change_log ccl on fc.id = ccl.case_id

            and ccl.create_time >= #{startTime,jdbcType=BIGINT}


            and ccl.create_time <= #{endTime,jdbcType=BIGINT}



        inner join (
            select case_id 
            from spotter_efficiency.test_plan_case_metrics
            where 1=1

                and create_time >= #{startTime,jdbcType=BIGINT}


                and create_time <= #{endTime,jdbcType=BIGINT}

            group by case_id
            having sum(exec_count) >= 3
        ) cer_high on fc.id = cer_high.case_id



where fc.deleted = 0

    and fc.create_user = #{dimensionValue,jdbcType=VARCHAR}


    and fc.project_id = #{dimensionValue,jdbcType=VARCHAR}





        and fc.create_time >= #{startTime,jdbcType=BIGINT}


        and fc.create_time <= #{endTime,jdbcType=BIGINT}

select count(distinct case when tpcm.first_exec_result is not null then tpcm.case_id end) as first_exec_count, count(distinct case when tpcm.first_exec_result = 'SUCCESS' then tpcm.case_id end) as first_pass_count, count(distinct case when tpcm.exec_count > 0 then tpcm.case_id end) as executed_case_count, sum(tpcm.exec_count) as total_exec_count, count(distinct case when tpcm.is_blocked_run = 0 and tpcm.last_exec_result = 'SUCCESS' then tpcm.case_id end) as success_without_block_count, -- 平均用例执行时长 = 总执行时长 / 执行次数 round(sum(tpcm.total_time_ms) / nullif(sum(tpcm.exec_count), 0)) as avg_duration, sum(tpcm.total_time_ms) as total_duration, -- 手动用例执行热度 = Σ(高频用例的CS总分) / Σ(所有用例的CS总分) × 100% -- 高频用例：执行次数 >= 3（包含3次） sum(case when tpcm.exec_count >= 3 then coalesce(cmd.cs_score, 0) else 0 end) as high_freq_cs_total, sum(coalesce(cmd.cs_score, 0)) as all_exec_cs_total from spotter_efficiency.test_plan_case_metrics tpcm left join spotter_efficiency.case_metrics_detail cmd on tpcm.case_id = cmd.case_id where tpcm.case_id in
#{caseId,jdbcType=VARCHAR}
and tpcm.create_time >= #{startTime,jdbcType=BIGINT}
and tpcm.create_time <= #{endTime,jdbcType=BIGINT}

select
    (select count(*) from (
        select cer.plan_id, cer.case_id
        from spotter_efficiency.case_execution_record cer
        where cer.case_id in

            #{caseId,jdbcType=VARCHAR}


            and cer.create_time >= #{startTime,jdbcType=BIGINT}


            and cer.create_time <= #{endTime,jdbcType=BIGINT}

        group by cer.plan_id, cer.case_id
    ) tot) as first_exec_count,
    (select count(*) from (
        select cer.plan_id, cer.case_id
        from spotter_efficiency.case_execution_record cer
        inner join (
            select plan_id, case_id, min(create_time) as first_time
            from spotter_efficiency.case_execution_record
            where case_id in

                #{caseId,jdbcType=VARCHAR}


                and create_time >= #{startTime,jdbcType=BIGINT}


                and create_time <= #{endTime,jdbcType=BIGINT}

            group by plan_id, case_id
        ) first_t on first_t.plan_id COLLATE utf8mb4_general_ci = cer.plan_id COLLATE utf8mb4_general_ci
            and first_t.case_id COLLATE utf8mb4_general_ci = cer.case_id COLLATE utf8mb4_general_ci
            and first_t.first_time = cer.create_time
        where cer.case_id in

            #{caseId,jdbcType=VARCHAR}


            and cer.create_time >= #{startTime,jdbcType=BIGINT}


            and cer.create_time <= #{endTime,jdbcType=BIGINT}

        and cer.exec_result in ('SUCCESS','PASS')
    ) fp) as first_pass_count

select sum(pa.parent_exec_count) as total_exec_count, sum(pa.parent_duration) as total_duration, round(sum(pa.parent_duration) / nullif(sum(pa.parent_exec_count), 0)) as avg_duration, sum(case when pa.parent_exec_count >= 3 then coalesce(cmd_p.cs_score, 0) else 0 end) as high_freq_cs_total, sum(coalesce(cmd_p.cs_score, 0)) as all_exec_cs_total from ( select coalesce(cmd.source_case_id, tpcm.case_id) as parent_id, sum(tpcm.exec_count) as parent_exec_count, sum(tpcm.total_time_ms) as parent_duration from spotter_efficiency.test_plan_case_metrics tpcm left join spotter_efficiency.case_metrics_detail cmd on tpcm.case_id COLLATE utf8mb4_general_ci = cmd.case_id COLLATE utf8mb4_general_ci inner join functional_case fc on fc.id COLLATE utf8mb4_general_ci = coalesce(cmd.source_case_id, tpcm.case_id) COLLATE utf8mb4_general_ci and fc.deleted = 0 inner join functional_case_module fcm on fc.module_id = fcm.id and fcm.name = #{regressionModuleName,jdbcType=VARCHAR} where 1=1
and tpcm.project_id = #{projectId,jdbcType=VARCHAR}
and tpcm.create_time >= #{startTime,jdbcType=BIGINT}
and tpcm.create_time <= #{endTime,jdbcType=BIGINT}
group by coalesce(cmd.source_case_id, tpcm.case_id) ) pa left join spotter_efficiency.case_metrics_detail cmd_p on cmd_p.case_id COLLATE utf8mb4_general_ci = pa.parent_id COLLATE utf8mb4_general_ci

select count(distinct ccl.case_id)
from spotter_efficiency.case_change_log ccl
where (ccl.change_reason is null or ccl.change_reason != 'CASE_COPY')

    and ccl.create_time >= #{startTime,jdbcType=BIGINT}


    and ccl.create_time <= #{endTime,jdbcType=BIGINT}

and ccl.case_id in (
    select distinct tpfc.functional_case_id
    from test_plan_functional_case tpfc
    inner join spotter_aegis.test_plan tp on tpfc.test_plan_id = tp.id
    where (tp.group_id = #{groupId,jdbcType=VARCHAR} and tp.type = 'TEST_PLAN') or tp.id = #{groupId,jdbcType=VARCHAR}
)

select 
    coalesce(sum(tpm.total_actual_exec_ms), 0) as total_actual_exec_ms,
    count(distinct tp.id) as exec_plan_count
from spotter_efficiency.test_plan_metrics tpm
inner join spotter_aegis.test_plan tp on tpm.test_plan_id COLLATE utf8mb4_general_ci = tp.id COLLATE utf8mb4_general_ci
where tp.group_id in (
    select tpg.id
    from spotter_aegis.test_plan tpg
    where tpg.type = 'GROUP'

        and tpg.project_id = #{projectId,jdbcType=VARCHAR}


        and tpg.create_time >= #{startTime,jdbcType=BIGINT}


        and tpg.create_time <= #{endTime,jdbcType=BIGINT}


        and tpg.feishu_story_id COLLATE utf8mb4_general_ci in

            #{storyId,jdbcType=VARCHAR}


)
and tp.type = 'TEST_PLAN'

select coalesce(sum(mss.test_analysis_time * 8 * 60 * 60 * 1000), 0) as total_actual_write_ms, count(distinct mss.story_id) as write_story_count from spotter_efficiency.meego_story_stats mss where mss.story_id COLLATE utf8mb4_general_ci in ( select distinct tpg.feishu_story_id COLLATE utf8mb4_general_ci from spotter_aegis.test_plan tpg where tpg.type = 'GROUP' and tpg.feishu_story_id is not null and tpg.feishu_story_id != ''
and tpg.project_id = #{projectId,jdbcType=VARCHAR}
and tpg.create_time >= #{startTime,jdbcType=BIGINT}
and tpg.create_time <= #{endTime,jdbcType=BIGINT}
and tpg.feishu_story_id COLLATE utf8mb4_general_ci in
#{storyId,jdbcType=VARCHAR}
) and mss.test_analysis_time is not null and mss.test_analysis_time > 0

select coalesce(sum(cmd.algo_expected_write_ms), 0) as total_expected_write_ms, coalesce(sum(cmd.algo_expected_exec_ms), 0) as total_expected_exec_ms, count(cmd.case_id) as case_count from spotter_aegis.test_plan tpg inner join spotter_aegis.test_plan tp on tp.group_id = tpg.id and tp.type = 'TEST_PLAN' inner join spotter_efficiency.test_plan_case_metrics tpcm on tp.id COLLATE utf8mb4_general_ci = tpcm.test_plan_id COLLATE utf8mb4_general_ci inner join spotter_efficiency.case_metrics_detail cmd on tpcm.case_id COLLATE utf8mb4_general_ci = cmd.case_id COLLATE utf8mb4_general_ci where tpg.type = 'GROUP' and tpg.feishu_story_id is not null and tpg.feishu_story_id != ''
and tpg.project_id = #{projectId,jdbcType=VARCHAR}
and tpg.create_time >= #{startTime,jdbcType=BIGINT}
and tpg.create_time <= #{endTime,jdbcType=BIGINT}
and tpg.feishu_story_id COLLATE utf8mb4_general_ci in
#{storyId,jdbcType=VARCHAR}

select cmd.complexity_level as complexity_level, coalesce(sum(cmd.algo_expected_write_ms), 0) as expected_write_ms, coalesce(sum(cmd.algo_expected_exec_ms), 0) as expected_exec_ms, count(cmd.case_id) as case_count from spotter_aegis.test_plan tpg inner join spotter_aegis.test_plan tp on tp.group_id = tpg.id and tp.type = 'TEST_PLAN' inner join spotter_efficiency.test_plan_case_metrics tpcm on tp.id COLLATE utf8mb4_general_ci = tpcm.test_plan_id COLLATE utf8mb4_general_ci inner join spotter_efficiency.case_metrics_detail cmd on tpcm.case_id COLLATE utf8mb4_general_ci = cmd.case_id COLLATE utf8mb4_general_ci where tpg.type = 'GROUP' and tpg.feishu_story_id is not null and tpg.feishu_story_id != '' and cmd.complexity_level is not null
and tpg.project_id = #{projectId,jdbcType=VARCHAR}
and tpg.create_time >= #{startTime,jdbcType=BIGINT}
and tpg.create_time <= #{endTime,jdbcType=BIGINT}
and tpg.feishu_story_id COLLATE utf8mb4_general_ci in
#{storyId,jdbcType=VARCHAR}
group by cmd.complexity_level

select 
    change_reason,
    count(distinct case_id) as count
from spotter_efficiency.case_change_log
where 1=1
and change_reason != 'CASE_COPY'

    and project_id = #{projectId,jdbcType=VARCHAR}


    and operator = #{userId,jdbcType=VARCHAR}


    and create_time >= #{startTime,jdbcType=BIGINT}


    and create_time <= #{endTime,jdbcType=BIGINT}


    and case_id in

        #{caseId,jdbcType=VARCHAR}


group by change_reason
order by count desc

select 
    block_reason,
    count(distinct case_id) as count
from spotter_efficiency.test_plan_case_metrics
where is_blocked_run = 1
and block_reason is not null

    and project_id = #{projectId,jdbcType=VARCHAR}


    and create_time >= #{startTime,jdbcType=BIGINT}


    and create_time <= #{endTime,jdbcType=BIGINT}


    and case_id in

        #{caseId,jdbcType=VARCHAR}


group by block_reason
order by count desc

select count(distinct case_id)
from spotter_efficiency.test_plan_case_metrics
where case_id in

    #{caseId,jdbcType=VARCHAR}

and exec_count > 0

    and create_time >= #{startTime,jdbcType=BIGINT}


    and create_time <= #{endTime,jdbcType=BIGINT}

select COALESCE(SUM(tpm.total_defect_count), 0)
from spotter_efficiency.test_plan_metrics tpm
where tpm.test_plan_id in (
    select distinct test_plan_id
    from spotter_efficiency.test_plan_case_metrics
    where case_id in

        #{caseId,jdbcType=VARCHAR}

)

    and tpm.last_calc_time >= #{startTime,jdbcType=BIGINT}


    and tpm.last_calc_time <= #{endTime,jdbcType=BIGINT}

select cmd.case_id as caseId, cmd.cs_score as csScore, cmd.complexity_level as complexityLevel, cmd.algo_expected_write_ms as algoExpectedWriteMs, cmd.algo_expected_exec_ms as algoExpectedExecMs, cmd.case_source_type as caseSourceType, cmd.reuse_type as reuseType, cmd.create_time as createTime, cmd.update_time as updateTime from spotter_efficiency.case_metrics_detail cmd inner join functional_case fc on fc.id COLLATE utf8mb4_general_ci = cmd.case_id COLLATE utf8mb4_general_ci and (fc.deleted IS NULL OR fc.deleted = 0)
inner join functional_case fc_src on cmd.source_case_id COLLATE utf8mb4_general_ci = fc_src.id COLLATE utf8mb4_general_ci and fc_src.deleted = 0 inner join functional_case_module fcm on fc_src.module_id = fcm.id and fcm.name in
#{name,jdbcType=VARCHAR}
where 1=1
and cmd.source_case_id is not null
and cmd.project_id in
#{id,jdbcType=VARCHAR}
and cmd.project_id = #{projectId,jdbcType=VARCHAR}
and cmd.case_source_type in ('REUSE', 'COPY')
and cmd.create_time >= #{startTime,jdbcType=BIGINT}
and cmd.create_time <= #{endTime,jdbcType=BIGINT}

select count(distinct cmd.case_id)
from spotter_efficiency.case_metrics_detail cmd

    inner join functional_case fc on cmd.case_id = fc.id

where 1=1

    and cmd.project_id = #{projectId,jdbcType=VARCHAR}


    and fc.create_user = #{userId,jdbcType=VARCHAR}

and cmd.case_source_type in ('REUSE', 'COPY')

    and cmd.create_time >= #{startTime,jdbcType=BIGINT}


    and cmd.create_time <= #{endTime,jdbcType=BIGINT}

select count(distinct case_id)
from spotter_efficiency.case_change_log
where 1=1

    and project_id = #{projectId,jdbcType=VARCHAR}


    and operator = #{userId,jdbcType=VARCHAR}


    and create_time >= #{startTime,jdbcType=BIGINT}


    and create_time <= #{endTime,jdbcType=BIGINT}

select mss.story_id as story_id, mss.story_name as story_name, mss.defect_count as defect_count, mss.test_analysis_time as test_analysis_time, count(distinct tp.id) as related_test_plan_count, count(distinct tpcm.case_id) as related_case_count from spotter_efficiency.meego_story_stats mss left join spotter_aegis.test_plan tp on mss.story_id COLLATE utf8mb4_general_ci = tp.feishu_story_id COLLATE utf8mb4_general_ci
and tp.project_id COLLATE utf8mb4_general_ci = #{projectId,jdbcType=VARCHAR}
and tp.create_time >= #{startTime,jdbcType=BIGINT}
and tp.create_time <= #{endTime,jdbcType=BIGINT}
left join spotter_efficiency.test_plan_case_metrics tpcm on tp.id COLLATE utf8mb4_general_ci = tpcm.test_plan_id COLLATE utf8mb4_general_ci where 1=1
and (mss.story_name like concat('%', #{keyword,jdbcType=VARCHAR}, '%') or mss.story_id like concat('%', #{keyword,jdbcType=VARCHAR}, '%'))
group by mss.story_id, mss.story_name, mss.defect_count, mss.test_analysis_time having count(distinct tp.id) > 0 order by related_case_count desc limit 100

select distinct tpcm.case_id
from spotter_aegis.test_plan tp
inner join spotter_efficiency.test_plan_case_metrics tpcm 
    on tp.id COLLATE utf8mb4_general_ci = tpcm.test_plan_id COLLATE utf8mb4_general_ci
where tp.feishu_story_id COLLATE utf8mb4_general_ci in

    #{storyId,jdbcType=VARCHAR}


    and tp.create_time >= #{startTime,jdbcType=BIGINT}


    and tp.create_time <= #{endTime,jdbcType=BIGINT}

select ccl.case_id as case_id, coalesce(fc.name, ccl.case_id) as case_name, fc.num as case_num, cmd.cs_score as cs_score, cmd.complexity_level as complexity_level, (select tp2.feishu_story_id from spotter_efficiency.test_plan_case_metrics tpcm2 inner join spotter_aegis.test_plan tp2 on tpcm2.test_plan_id COLLATE utf8mb4_general_ci = tp2.id COLLATE utf8mb4_general_ci where tpcm2.case_id COLLATE utf8mb4_general_ci = ccl.case_id COLLATE utf8mb4_general_ci limit 1) as story_id, (select mss2.story_name from spotter_efficiency.test_plan_case_metrics tpcm2 inner join spotter_aegis.test_plan tp2 on tpcm2.test_plan_id COLLATE utf8mb4_general_ci = tp2.id COLLATE utf8mb4_general_ci inner join spotter_efficiency.meego_story_stats mss2 on tp2.feishu_story_id COLLATE utf8mb4_general_ci = mss2.story_id COLLATE utf8mb4_general_ci where tpcm2.case_id COLLATE utf8mb4_general_ci = ccl.case_id COLLATE utf8mb4_general_ci limit 1) as story_name, (select tp2.id from spotter_efficiency.test_plan_case_metrics tpcm2 inner join spotter_aegis.test_plan tp2 on tpcm2.test_plan_id COLLATE utf8mb4_general_ci = tp2.id COLLATE utf8mb4_general_ci where tpcm2.case_id COLLATE utf8mb4_general_ci = ccl.case_id COLLATE utf8mb4_general_ci limit 1) as test_plan_id, (select tp2.name from spotter_efficiency.test_plan_case_metrics tpcm2 inner join spotter_aegis.test_plan tp2 on tpcm2.test_plan_id COLLATE utf8mb4_general_ci = tp2.id COLLATE utf8mb4_general_ci where tpcm2.case_id COLLATE utf8mb4_general_ci = ccl.case_id COLLATE utf8mb4_general_ci limit 1) as test_plan_name, ccl.change_reason as change_reason, max(ccl.create_time) as create_time from spotter_efficiency.case_change_log ccl left join functional_case fc on ccl.case_id COLLATE utf8mb4_general_ci = fc.id COLLATE utf8mb4_general_ci and fc.deleted = 0 left join spotter_efficiency.case_metrics_detail cmd on ccl.case_id COLLATE utf8mb4_general_ci = cmd.case_id COLLATE utf8mb4_general_ci where ccl.change_reason = #{changeReason,jdbcType=VARCHAR}
and ccl.project_id = #{projectId,jdbcType=VARCHAR}
and (fc.create_user = #{userId,jdbcType=VARCHAR} or fc.id is null)
and ccl.create_time >= #{startTime,jdbcType=BIGINT}
and ccl.create_time <= #{endTime,jdbcType=BIGINT}
group by ccl.case_id, fc.name, fc.num, cmd.cs_score, cmd.complexity_level, ccl.change_reason order by create_time desc, case_num desc limit 100

select tpcm.case_id as case_id, coalesce(fc.name, tpcm.case_id) as case_name, fc.num as case_num, cmd.cs_score as cs_score, cmd.complexity_level as complexity_level, (select tp2.feishu_story_id from spotter_efficiency.test_plan_case_metrics tpcm2 inner join spotter_aegis.test_plan tp2 on tpcm2.test_plan_id COLLATE utf8mb4_general_ci = tp2.id COLLATE utf8mb4_general_ci where tpcm2.case_id COLLATE utf8mb4_general_ci = tpcm.case_id COLLATE utf8mb4_general_ci and tpcm2.block_reason = #{blockReason,jdbcType=VARCHAR} and tpcm2.is_blocked_run = 1 limit 1) as story_id, (select mss2.story_name from spotter_efficiency.test_plan_case_metrics tpcm2 inner join spotter_aegis.test_plan tp2 on tpcm2.test_plan_id COLLATE utf8mb4_general_ci = tp2.id COLLATE utf8mb4_general_ci inner join spotter_efficiency.meego_story_stats mss2 on tp2.feishu_story_id COLLATE utf8mb4_general_ci = mss2.story_id COLLATE utf8mb4_general_ci where tpcm2.case_id COLLATE utf8mb4_general_ci = tpcm.case_id COLLATE utf8mb4_general_ci and tpcm2.block_reason = #{blockReason,jdbcType=VARCHAR} and tpcm2.is_blocked_run = 1 limit 1) as story_name, (select tp2.id from spotter_efficiency.test_plan_case_metrics tpcm2 inner join spotter_aegis.test_plan tp2 on tpcm2.test_plan_id COLLATE utf8mb4_general_ci = tp2.id COLLATE utf8mb4_general_ci where tpcm2.case_id COLLATE utf8mb4_general_ci = tpcm.case_id COLLATE utf8mb4_general_ci and tpcm2.block_reason = #{blockReason,jdbcType=VARCHAR} and tpcm2.is_blocked_run = 1 limit 1) as test_plan_id, (select tp2.name from spotter_efficiency.test_plan_case_metrics tpcm2 inner join spotter_aegis.test_plan tp2 on tpcm2.test_plan_id COLLATE utf8mb4_general_ci = tp2.id COLLATE utf8mb4_general_ci where tpcm2.case_id COLLATE utf8mb4_general_ci = tpcm.case_id COLLATE utf8mb4_general_ci and tpcm2.block_reason = #{blockReason,jdbcType=VARCHAR} and tpcm2.is_blocked_run = 1 limit 1) as test_plan_name, tpcm.block_reason as block_reason, max(tpcm.create_time) as create_time from spotter_efficiency.test_plan_case_metrics tpcm left join functional_case fc on tpcm.case_id COLLATE utf8mb4_general_ci = fc.id COLLATE utf8mb4_general_ci and fc.deleted = 0 left join spotter_efficiency.case_metrics_detail cmd on tpcm.case_id COLLATE utf8mb4_general_ci = cmd.case_id COLLATE utf8mb4_general_ci where tpcm.block_reason = #{blockReason,jdbcType=VARCHAR} and tpcm.is_blocked_run = 1
and tpcm.project_id = #{projectId,jdbcType=VARCHAR}
and (fc.create_user = #{userId,jdbcType=VARCHAR} or fc.id is null)
and tpcm.create_time >= #{startTime,jdbcType=BIGINT}
and tpcm.create_time <= #{endTime,jdbcType=BIGINT}
group by tpcm.case_id, fc.name, fc.num, cmd.cs_score, cmd.complexity_level, tpcm.block_reason order by create_time desc, case_num desc limit 100
